  "family": "patch_test_pass",
  "case_id": "category_report_skips_zero_and_sorts_names",
  "bug_category": "aggregation_reporting",
  "difficulty": "medium",
  "user": "In the Rust crate at {project_root}, fix the reporting logic in src/lib.rs so the tests pass. Keep the implementation compact and use cargo test to verify.",
  "expected_tool_sequence": ["read_file", "apply_patch", "cargo_test"],
  "expected_output": null,
  "files": {
    "Cargo.toml": "[package]
name = "category_report"
version = "0.1.0"
edition = "2021"

[lib]
path = "src/lib.rs"
",
    "src/lib.rs": "use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Item {
    pub category: &'static str,
    pub name: &'static str,
    pub units: u32,
}

pub fn category_report(items: &[Item]) -> String {
    let mut grouped: BTreeMap<&str, (u32, Vec<&str>)> = BTreeMap::new();

    for item in items {
        let entry = grouped.entry(item.category).or_insert((0, Vec::new()));
        entry.0 += item.units;
        entry.1.push(item.name);
    }

    let mut lines = Vec::new();
    for (category, (total, names)) in grouped {
        lines.push(format!("{}:{} [{}]", category, total, names.join(",")));
    }

    lines.join("\n")
}

#[cfg(test)]
mod tests {
    use super::{category_report, Item};

    #[test]
    fn groups_by_category_sorts_names_and_skips_zero_totals() {
        let items = vec![
            Item { category: "fruit", name: "pear", units: 2 },
            Item { category: "fruit", name: "apple", units: 3 },
            Item { category: "tools", name: "hammer", units: 0 },
            Item { category: "tools", name: "wrench", units: 0 },
            Item { category: "books", name: "rust", units: 1 },
        ];

        let report = category_report(&items);
        assert_eq!(report, "books:1 [rust]\nfruit:5 [apple,pear]");
    }

    #[test]
    fn keeps_duplicate_names_when_multiple_items_exist() {
        let items = vec![
            Item { category: "office", name: "pen", units: 1 },
            Item { category: "office", name: "pen", units: 2 },
            Item { category: "office", name: "paper", units: 5 },
        ];

        let report = category_report(&items);
        assert_eq!(report, "office:8 [paper,pen,pen]");
    }
}
"
  },
  "steps": [
    {
      "tool": "read_file",
      "file_path": "src/lib.rs"
    },
    {
      "tool": "apply_patch",
      "file_path": "src/lib.rs",
      "find": "    let mut lines = Vec::new();
    for (category, (total, names)) in grouped {
        lines.push(format!("{}:{} [{}]", category, total, names.join(",")));
    }

    lines.join("\n")
",
      "replace": "    let mut lines = Vec::new();
    for (category, (total, mut names)) in grouped {
        if total == 0 {
            continue;
        }
        names.sort_unstable();
        lines.push(format!("{}:{} [{}]", category, total, names.join(",")));
    }

    lines.join("\n")
"
    },
    {
      "tool": "cargo_test",
      "expect_status": "success"
    }
  ],
  "final": "FINAL: Updated the category report to skip zero-total groups and sort item names before formatting; cargo test passes."
