    match action {
        Action::View => true,
        Action::Edit => role != Role::Guest,
        Action::Delete => owns_post,
        Action::Publish => role == Role::Member,
    }
}
",
      "replace": "pub fn can_perform(role: Role, action: Action, owns_post: bool) -> bool {
    match action {
        Action::View => true,
        Action::Edit => role != Role::Guest,
        Action::Delete => role == Role::Admin || (role == Role::Member && owns_post),
        Action::Publish => role == Role::Member || role == Role::Admin,
