pub enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
    Cancelled,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    StartWork,
    Resolve,
    Close,
    Reopen,
    Cancel,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Ticket {
    pub status: Status,
    pub assignee: Option<&'static str>,
    pub resolution: Option<&'static str>,
    pub closed_at: Option<u32>,
    pub revision: u32,
}

impl Ticket {
    pub fn new() -> Self {
        Self {
            status: Status::Open,
            assignee: None,
            resolution: None,
            closed_at: None,
            revision: 0,
        }
    }

    pub fn apply(&mut self, event: Event, now: u32) {
        match event {
            Event::StartWork => {
                if self.status == Status::Open {
                    self.status = Status::InProgress;
                    if self.assignee.is_none() {
                        self.assignee = Some("system");
                    }
                }
            }
            Event::Resolve => {
                if matches!(self.status, Status::Open | Status::InProgress) {
                    self.status = Status::Resolved;
                    if self.resolution.is_none() {
                        self.resolution = Some("fixed");
                    }
                }
            }
            Event::Close => {
                if self.status == Status::Resolved {
                    self.status = Status::Closed;
                    self.closed_at = Some(now);
                }
            }
            Event::Reopen => {
                if matches!(self.status, Status::Resolved | Status::Closed | Status::Cancelled) {
                    self.status = Status::Open;
                    self.revision += 1;
                }
            }
            Event::Cancel => {
                self.status = Status::Cancelled;
                self.closed_at = Some(now);
            }
        }
    }
}

