        let existing = [Booking::new("A", 10, 20)];
        let req = Booking::new("A", 20, 30);
        assert!(can_book(&existing, &req));
    }

    #[test]
    fn overlapping_same_room_is_rejected() {
        let existing = [Booking::new("A", 10, 20)];
        let req = Booking::new("A", 19, 25);
        assert!(!can_book(&existing, &req));
    }

