        let req = Booking::new("A", 12, 14);
        assert!(can_book(&existing, &req));
    }

    #[test]
    fn zero_length_request_is_invalid() {
        let existing = [Booking::new("A", 1, 5)];
        let req = Booking::new("A", 7, 7);
        assert!(!can_book(&existing, &req));
    }

    #[test]
    fn reversed_request_is_invalid() {
        let existing = [Booking::new("A", 1, 5)];
        let req = Booking::new("A", 9, 3);
