    "src/main.rs": "use std::fmt::Write;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    Open,
    InProgress,
    Closed,
}

#[derive(Clone, Debug)]
struct Ticket {
    id: &'static str,
    status: Status,
    assignee: Option<&'static str>,
}

enum Event {
    Create { id: &'static str },
    Assign { id: &'static str, user: &'static str },
    Unassign { id: &'static str },
    Close { id: &'static str },
    Reopen { id: &'static str },
}

fn apply(t: &mut Ticket, e: &Event) {
    match *e {
        Event::Assign { user, .. } => {
            t.assignee = Some(user);
            t.status = Status::InProgress;
        }
        Event::Unassign { .. } => {
            t.assignee = None;
        }
        Event::Close { .. } => {
            t.status = Status::Closed;
        }
        Event::Reopen { .. } => {
            t.status = Status::InProgress;
        }
        Event::Create { .. } => {}
    }
}

fn main() {
    let events = [
        Event::Create { id: "T1" },
        Event::Assign { id: "T1", user: "alice" },
        Event::Close { id: "T1" },
        Event::Reopen { id: "T1" },
        Event::Create { id: "T2" },
        Event::Assign { id: "T2", user: "bob" },
        Event::Close { id: "T2" },
        Event::Reopen { id: "T2" },
        Event::Close { id: "T2" },
        Event::Create { id: "T3" },
        Event::Assign { id: "T3", user: "cara" },
        Event::Unassign { id: "T3" },
    ];

    let mut tickets: Vec<Ticket> = Vec::new();
    for e in &events {
        match *e {
            Event::Create { id } => tickets.push(Ticket {
                id,
                status: Status::Open,
                assignee: None,
            }),
            Event::Assign { id, .. }
            | Event::Unassign { id }
            | Event::Close { id }
            | Event::Reopen { id } => {
                if let Some(t) = tickets.iter_mut().find(|t| t.id == id) {
                    apply(t, e);
                }
            }
        }
    }

    tickets.sort_by_key(|t| t.id);

    let mut open = 0;
    let mut in_progress = 0;
    let mut closed = 0;
    let mut unassigned_open = 0;
    let mut out = String::new();

    for t in &tickets {
        match t.status {
            Status::Open => open += 1,
            Status::InProgress => in_progress += 1,
            Status::Closed => closed += 1,
        }
        if t.status != Status::Closed && t.assignee.is_none() {
            unassigned_open += 1;
        }
        let status = match t.status {
            Status::Open => "Open",
            Status::InProgress => "InProgress",
            Status::Closed => "Closed",
        };
        let assignee = t.assignee.unwrap_or("-");
        let _ = writeln!(&mut out, "{}:{}:{}", t.id, status, assignee);
    }

    let _ = write!(
        &mut out,
        "open={} in_progress={} closed={} unassigned_open={}",
        open, in_progress, closed, unassigned_open
    );

    print!("{}", out);
}
