    Resume(&'a str),
    Resolve(&'a str),
    Reopen(&'a str),
}

fn apply_event(states: &mut BTreeMap<String, Status>, event: Event<'_>) {
    match event {
        Event::Create(id) => {
            states.entry(id.to_string()).or_insert(Status::New);
