fn merge(base: Config, file: Config, env: Config, cli: Config) -> Config {
    Config {
        host: pick(pick(pick(base.host, cli.host), env.host), file.host),
        port: pick_num(pick_num(pick_num(base.port, cli.port), env.port), file.port),
