            "active" => match value.trim() {
                "true" => active = true,
                "false" => active = false,
                _ => return Err("invalid active".to_string()),
            },
            _ => return Err(format!("unknown field: {}", key.trim())),
        }
    }

    Ok(Person { name, age, active })
}

