        entry.orders += 1;
        entry.items += order.item_count;
        entry.revenue_cents += order.item_count * order.unit_price_cents;
    }

    let mut out: Vec<_> = grouped.into_values().collect();
    out.sort_by(|a, b| a.customer.cmp(&b.customer));
    out
