    Admin,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Action {
    View,
    Comment,
    Delete,
    Suspend,
}

pub fn is_allowed(role: Role, action: Action, owner: bool, flagged: bool) -> bool {
    match action {
        Action::View => true,
        Action::Comment => match role {
            Role::Guest => false,
            Role::Member | Role::Admin => true,
        },
        Action::Delete => match role {
            Role::Admin => true,
            Role::Member => owner,
            Role::Guest => false,
