pub fn summarize(records: &[(&str, i32, bool)]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();

    for &(category, amount, active) in records {
        if active {
            *totals.entry(category).or_insert(0) += amount;
        }
    }

    let mut lines = Vec::new();
    let grand_total: i32 = totals.values().copied().sum();

    for (category, total) in totals {
