    pub port: Option<u16>,
    pub timeout_ms: Option<u32>,
    pub lock_timeout: bool,
}

pub fn merge_config(
    defaults: &Config,
    file: Option<&PartialConfig>,
    env: Option<&PartialConfig>,
) -> Config {
    let mut out = defaults.clone();

    if let Some(file_cfg) = file {
        if let Some(host) = &file_cfg.host {
            out.host = host.clone();
        }
        if let Some(port) = file_cfg.port {
            out.port = port;
        }
        if let Some(timeout) = file_cfg.timeout_ms {
            out.timeout_ms = timeout;
        }
    }

    if let Some(env_cfg) = env {
        if let Some(host) = &env_cfg.host {
            out.host = host.clone();
        }
        if let Some(port) = env_cfg.port {
            out.port = port;
        }
        if let Some(timeout) = env_cfg.timeout_ms {
            out.timeout_ms = timeout;
        }
    }

    out
}

