pub fn summarize_sales(sales: &[Sale]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();

    for sale in sales {
        let entry = totals.entry(sale.category).or_insert(0);
        if !sale.refunded {
            *entry += sale.amount;
        }
    }

    let mut lines = Vec::new();
    for (category, total) in totals {
