pub struct Item {
    pub id: u32,
    pub name: String,
    pub active: bool,
}

pub fn parse_items(input: &str) -> Result<Vec<Item>, String> {
    let mut out = Vec::new();

    for (idx, line) in input.lines().enumerate() {
        let line = line.trim();
        if line.is_empty() {
            continue;
        }

        let parts: Vec<_> = line.split(',').map(str::trim).collect();
        if parts.len() != 3 {
            return Err(format!("line {}: expected 3 fields", idx + 1));
        }

        let id = parts[0]
            .parse::<u32>()
            .map_err(|_| format!("line {}: invalid id", idx + 1))?;

        let name = parts[1].to_string();

        let active = match parts[2] {
            "true" | "yes" | "1" => true,
            "false" | "no" | "0" => false,
            _ => return Err(format!("line {}: invalid active flag", idx + 1)),
        };

        out.push(Item { id, name, active });
    }

    Ok(out)
}

