pub struct Sale<'a> {
    pub region: &'a str,
    pub amount_cents: i64,
    pub refunded: bool,
}

pub fn summarize_sales(sales: &[Sale<'_>]) -> String {
    let mut totals: Vec<(&str, i64)> = Vec::new();

    for sale in sales {
        let mut found = false;
        for (region, total) in &mut totals {
            if *region == sale.region {
                *total += sale.amount_cents;
                found = true;
                break;
            }
        }
        if !found {
            totals.push((sale.region, sale.amount_cents));
        }
    }

    totals.sort_by(|a, b| a.0.cmp(b.0));

    let mut out = String::new();
    for (region, total) in totals {
        if !out.is_empty() {
            out.push('\n');
        }
        out.push_str(region);
        out.push(':');
        out.push_str(&(total / 100).to_string());
        out.push('.');
        out.push_str(&format!("{:02}", total.abs() % 100));
    }
    out
}

