pub struct Player {
    pub name: String,
    pub wins: u32,
    pub draws: u32,
    pub losses: u32,
    pub points_for: u32,
    pub points_against: u32,
}

impl Player {
    fn points(&self) -> i32 {
        (self.wins * 3 + self.draws) as i32
    }

    fn point_diff(&self) -> i32 {
        self.points_for as i32 - self.points_against as i32
    }
}

pub fn leaderboard(players: &[Player]) -> Vec<String> {
    let mut rows = players.to_vec();
    rows.sort_by(|a, b| {
        b.points()
            .cmp(&a.points())
            .then_with(|| b.wins.cmp(&a.wins))
            .then_with(|| a.point_diff().cmp(&b.point_diff()))
            .then_with(|| a.name.cmp(&b.name))
    });

    rows.into_iter()
        .enumerate()
        .map(|(i, p)| {
            format!(
                "{}. {} [{} pts, diff {}]",
                i + 1,
                p.name,
                p.points(),
                p.point_diff()
            )
        })
        .collect()
}

