pub fn classify(kind: MessageKind, urgent: bool, retries: u8) -> (&'static str, Priority) {
    match kind {
        MessageKind::Email => {
            if urgent {
                ("fast-lane", Priority::High)
            } else {
                ("digest", Priority::Low)
            }
        }
        MessageKind::Sms => {
            if retries > 0 {
                ("retry", Priority::Normal)
            } else {
