    pub port: u16,
    pub tls: bool,
    pub retries: u8,
    pub timeout_ms: u64,
    pub features: Vec<String>,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub tls: Option<bool>,
    pub retries: Option<u8>,
    pub timeout_ms: Option<u64>,
    pub features: Option<Vec<String>>,
}

pub fn merge_config(
    defaults: &Config,
    file: Option<&PartialConfig>,
    env: Option<&PartialConfig>,
    cli: Option<&PartialConfig>,
) -> Config {
    let mut out = defaults.clone();

    for layer in [file, env, cli] {
        if let Some(cfg) = layer {
            if let Some(v) = &cfg.host {
                out.host = v.clone();
            }
            if let Some(v) = cfg.port {
                out.port = v;
            }
            if let Some(v) = cfg.tls {
                out.tls = v;
            }
            if let Some(v) = cfg.retries {
                out.retries = v;
            }
            if let Some(v) = cfg.timeout_ms {
                out.timeout_ms = v;
            }
            if let Some(v) = &cfg.features {
                if !v.is_empty() {
                    out.features.extend(v.iter().cloned());
                }
            }
        }
    }

    out
}

