pub enum State {
    Draft,
    Active,
    Paused,
    Completed,
    Canceled,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Pause,
    Resume,
    Complete,
    Cancel,
}

pub fn apply_event(state: State, event: Event) -> State {
    match (state, event) {
        (State::Draft, Event::Submit) => State::Active,
        (State::Draft, Event::Cancel) => State::Canceled,
        (State::Active, Event::Pause) => State::Paused,
        (State::Active, Event::Complete) => State::Completed,
        (State::Active, Event::Cancel) => State::Canceled,
        (State::Paused, Event::Resume) => State::Active,
        (State::Paused, Event::Complete) => State::Completed,
        (_, Event::Cancel) => State::Canceled,
        _ => state,
    }
}

pub fn apply_events(mut state: State, events: &[Event]) -> State {
    for &event in events {
