            Action::Edit => false,
            Action::Delete => false,
        },
        Resource::BetaLab => {
            if !beta_enabled {
                return false;
            }
            match action {
                Action::View => matches!(role, Role::Member | Role::Staff | Role::Admin),
                Action::Edit => matches!(role, Role::Staff),
                Action::Delete => matches!(role, Role::Admin),
            }
        }
    }
}

