  "files": {
    "Cargo.toml": "[package]
name = "ticket_state_transitions"
version = "0.1.0"
edition = "2021"
",
    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum Status {
    Open,
    InProgress,
    Blocked,
    Done,
}

impl Status {
    fn as_str(self) -> &'static str {
        match self {
            Status::Open => "open",
            Status::InProgress => "in_progress",
            Status::Blocked => "blocked",
            Status::Done => "done",
        }
    }
}

enum Event<'a> {
    Create(&'a str),
    Start(&'a str),
    Block(&'a str),
    Resume(&'a str),
    Finish(&'a str),
    Reopen(&'a str),
}

fn apply_event(state: &mut BTreeMap<String, Status>, event: Event<'_>) {
    match event {
        Event::Create(id) => {
            state.insert(id.to_string(), Status::Open);
        }
        Event::Start(id) => {
            if let Some(status) = state.get_mut(id) {
                *status = Status::InProgress;
            }
        }
        Event::Block(id) => {
            if let Some(status) = state.get_mut(id) {
                *status = Status::Blocked;
            }
        }
        Event::Resume(id) => {
            if let Some(status) = state.get_mut(id) {
                *status = Status::Open;
            }
        }
        Event::Finish(id) => {
            if let Some(status) = state.get_mut(id) {
                *status = Status::Done;
            }
        }
        Event::Reopen(id) => {
            if let Some(status) = state.get_mut(id) {
                *status = Status::Done;
            }
        }
    }
}

fn main() {
    let events = [
        Event::Create("A"),
        Event::Start("A"),
        Event::Finish("A"),
        Event::Create("B"),
        Event::Start("B"),
        Event::Reopen("B"),
        Event::Create("C"),
        Event::Start("C"),
        Event::Block("C"),
        Event::Resume("C"),
        Event::Block("C"),
    ];

    let mut state = BTreeMap::new();
    for event in events {
        apply_event(&mut state, event);
    }

    let mut lines = Vec::new();
    for (id, status) in state {
        lines.push(format!("{}:{}", id, status.as_str()));
    }
    println!("{}", lines.join("\n"));
}
