    "src/main.rs": "struct User {
    name: &'static str,
    active: bool,
    scores: &'static [i32],
}

fn build_report(users: &[User]) -> String {
    users
        .iter()
        .filter(|u| !u.active)
        .map(|u| {
            let total: i32 = u
                .scores
                .iter()
                .enumerate()
                .filter(|(idx, score)| idx % 2 == 1 && **score > 0)
                .map(|(_, score)| *score)
                .sum();
