        })
        .chain(std::iter::once(format!(
            "TOTAL={}",
            users
                .iter()
                .flat_map(|u| u.scores.iter())
                .copied()
                .filter(|s| *s > 0)
                .sum::<i32>()
        )))
        .collect::<Vec<_>>()
        .join("\n")
}

