    "src/main.rs": "enum Command {
    Build { target: &'static str, release: bool },
    Clean { cache_only: bool },
    Notify { channel: &'static str, urgent: bool },
    Archive { path: &'static str, compress: bool },
}

struct Summary {
    actions: Vec<String>,
    failures: usize,
    deferred: usize,
    risk: u32,
}

fn render(cmd: &Command) -> Result<(String, u32, bool), &'static str> {
    match cmd {
        Command::Build { target, release } => {
            let points = if *release { 5 } else { 1 };
            Ok((format!("build {target} {points}"), points, false))
        }
        Command::Clean { cache_only } => {
            if *cache_only {
                Ok(("clean all".to_string(), 0, false))
            } else {
                Ok(("skip cache".to_string(), 0, true))
            }
        }
        Command::Notify { channel, urgent } => {
            let level = if *urgent { "normal" } else { "high" };
            Ok((format!("notify {channel} {level}"), 3, false))
        }
        Command::Archive { path, compress } => {
            if *compress {
                Err("archive disabled")
            } else {
                Ok((format!("archive {path}"), 2, false))
            }
        }
    }
}

fn execute(cmds: &[Command]) -> Summary {
    let mut summary = Summary {
        actions: Vec::new(),
        failures: 0,
        deferred: 0,
        risk: 0,
    };

    for cmd in cmds {
        match render(cmd) {
            Ok((line, risk, deferred)) => {
                summary.actions.push(line);
                summary.risk += risk;
                if deferred {
                    summary.deferred += 1;
                }
            }
            Err(_) => summary.failures += 1,
        }
    }

    summary
}

fn main() {
