            urgent: true,
        },
        Command::Archive {
            path: "logs",
            compress: false,
        },
    ];

    let summary = execute(&cmds);
    for line in &summary.actions {
        println!("{line}");
    }
    println!(
        "actions={} failures={} deferred={} risk={}",
        summary.actions.len(),
        summary.failures,
        summary.deferred,
        summary.risk
    );
}
