    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy, PartialEq, Eq)]
enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
}

impl Status {
    fn as_str(&self) -> &'static str {
        match self {
            Status::Open => "Open",
            Status::InProgress => "InProgress",
            Status::Resolved => "Resolved",
            Status::Closed => "Closed",
        }
    }
}

fn apply(status: Status, event: &str) -> Status {
    match event {
        "start" => Status::InProgress,
        "resolve" => Status::InProgress,
        "reopen" => Status::Open,
        "close" => Status::Closed,
        _ => status,
    }
}

fn main() {
    let events = [
        ("T1", "start"),
        ("T1", "resolve"),
        ("T1", "close"),
        ("T2", "start"),
        ("T2", "reopen"),
        ("T3", "start"),
        ("T3", "resolve"),
    ];

    let mut tickets: BTreeMap<&str, Status> = BTreeMap::new();

    for (id, event) in events {
        let current = tickets.get(id).copied().unwrap_or(Status::Open);
        tickets.insert(id, apply(current, event));
    }

    for (id, status) in tickets {
        println!("{}:{}", id, status.as_str());
    }
}
