    retries: u8,
}

impl Config {
    fn merge(defaults: Config, file: PartialConfig, env: PartialConfig) -> Config {
        let host = file.host.unwrap_or(defaults.host);
        let port = file.port.unwrap_or(defaults.port);
        let mode = file.mode.unwrap_or(defaults.mode);
        let retries = file.retries.unwrap_or(defaults.retries);

        Config {
            host: env.host.unwrap_or(host),
            port: env.port.unwrap_or(port),
            mode: env.mode.unwrap_or(mode),
            retries,
        }
    }

    fn as_json(&self) -> String {
        format!(
            "{{\"host\":\"{}\",\"port\":{},\"mode\":\"{}\",\"retries\":{}}}",
            self.host, self.port, self.mode, self.retries
        )
    }
}

struct PartialConfig {
    host: Option<String>,
    port: Option<u16>,
    mode: Option<String>,
    retries: Option<u8>,
}

fn parse_env(entries: &[(&str, &str)]) -> PartialConfig {
    let mut cfg = PartialConfig {
        host: None,
        port: None,
        mode: None,
        retries: None,
    };

    for (key, value) in entries {
        match *key {
            "APP_HOST" => cfg.host = Some((*value).to_string()),
            "APP_PORT" => cfg.port = value.parse().ok(),
            "APP_MODE" => cfg.mode = Some((*value).to_string()),
            _ => {}
        }
    }

    cfg
}

fn main() {
    let defaults = Config {
        host: "localhost".to_string(),
        port: 8080,
        mode: "prod".to_string(),
        retries: 3,
    };

    let file = PartialConfig {
        host: Some("file.local".to_string()),
        port: Some(7000),
        mode: None,
        retries: Some(5),
    };

    let env = parse_env(&[
        ("APP_HOST", ""),
        ("APP_MODE", "dev"),
        ("APP_RETRIES", "9"),
    ]);

    let merged = Config::merge(defaults, file, env);
    println!("{}", merged.as_json());
}
