        Action::Warn("retrying sync"),
        Action::Error { code: 404, detail: "dropping packet" },
        Action::Noop,
    ];

    let mut counts = Counts::default();
    let mut lines = Vec::new();

    for action in &actions {
        lines.push(render(action, &mut counts));
    }

    lines.push(format!(
        "totals: start={} io={} warn={} error={} noop={}",
        counts.start, counts.io, counts.warn, counts.error, counts.noop
    ));

    println!("{}", lines.join("\n"));
