line 6: malformed",
  "files": {
    "Cargo.toml": "[package]
name = "csv_inventory_validation_recover"
version = "0.1.0"
edition = "2021"
",
    "src/main.rs": "use std::collections::HashSet;

const INPUT: &str = "sku,name,qty,price\nA12,Widget,3,4.50\nB07,Gadget,0,9.99\nC99,Thing,5,0\nA12,Widget XL,2,5.00\nD10,Broken\nE11,Valid Item,13,1.25\n";

fn validate(input: &str) -> String {
    let mut seen = HashSet::new();
    let mut valid = 0;
    let mut invalid = 0;
    let mut qty_sum = 0;
    let mut errors = Vec::new();

    for (idx, line) in input.lines().enumerate() {
        if idx == 0 || line.is_empty() {
            continue;
        }

        let parts: Vec<&str> = line.split(',').collect();
        if parts.len() < 3 {
            invalid += 1;
            errors.push(format!("line {}: malformed", idx + 1));
            continue;
        }

        let sku = parts[0];
        let qty = parts[2].parse::<i32>().unwrap_or(0);
        let price = parts.get(3).and_then(|s| s.parse::<f64>().ok()).unwrap_or(0.0);

        if seen.contains(sku) {
            invalid += 1;
            errors.push(format!("line {}: duplicate sku", idx + 1));
            continue;
        }
        seen.insert(sku.to_string());

        if qty < 0 {
            invalid += 1;
            errors.push(format!("line {}: nonpositive qty", idx + 1));
            continue;
        }

        if price < 0.0 {
