    let port = env.port.or(file.port).unwrap_or(port);
    let timeout = file.timeout.or(env.timeout).unwrap_or(timeout);
    let debug = file.debug.or(env.debug).or(cli.debug).unwrap_or(debug);

    Config {
        host,
        port,
        timeout,
        debug,
    }
}

