T3=closed",
  "files": {
    "Cargo.toml": "[package]
name = "ticket_state_transition_report"
version = "0.1.0"
edition = "2021"
",
    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
enum Status {
    Open,
    InProgress,
    Blocked,
    Closed,
}

impl Status {
    fn label(self) -> &'static str {
        match self {
            Status::Open => "open",
            Status::InProgress => "in_progress",
            Status::Blocked => "blocked",
            Status::Closed => "closed",
        }
    }
}

fn apply(status: Status, event: &str) -> Status {
    match event {
        "start" => Status::InProgress,
        "block" => Status::Blocked,
        "resume" => Status::Open,
        "close" => Status::Closed,
        "reopen" => Status::Open,
        _ => status,
    }
}

fn main() {
    let log = [
        ("T1", "start"),
        ("T1", "block"),
        ("T1", "resume"),
        ("T1", "close"),
        ("T2", "start"),
        ("T2", "block"),
        ("T2", "resume"),
        ("T3", "close"),
        ("T3", "reopen"),
        ("T3", "close"),
    ];

    let mut items: BTreeMap<&str, Status> = BTreeMap::new();
    for (id, event) in log {
        let current = *items.get(id).unwrap_or(&Status::Open);
        let next = apply(current, event);
        items.insert(id, next);
    }

    let mut counts: BTreeMap<&'static str, usize> = BTreeMap::new();
    for status in [Status::Open, Status::InProgress, Status::Blocked, Status::Closed] {
        counts.insert(status.label(), 0);
    }
    for status in items.values() {
        *counts.get_mut(status.label()).unwrap() += 1;
    }

    println!("open: {}", counts["open"]);
    println!("in_progress: {}", counts["in_progress"]);
    println!("blocked: {}", counts["blocked"]);
    println!("closed: {}", counts["closed"]);
