    "src/main.rs": "enum Action {
    Read,
    Write,
    Delete,
}

enum Event<'a> {
    Allow { path: &'a str, actions: Vec<Action> },
    Deny { path: &'a str, actions: Vec<Action> },
    Audit { name: &'a str, critical: bool },
}

fn action_name(a: &Action) -> &'static str {
    match a {
        Action::Read => "read",
        Action::Write => "write",
        Action::Delete => "delete",
    }
}

fn format_actions(actions: &[Action]) -> String {
    let mut out = String::new();
    for (i, a) in actions.iter().enumerate() {
        if i > 0 {
            out.push(',');
        }
        out.push_str(action_name(a));
    }
    out
}

fn render(event: &Event) -> String {
    match event {
        Event::Allow { path, actions } => {
            format!("allow: {} [{}]", path, format_actions(actions))
        }
        Event::Deny { path, actions } => {
            format!("deny: {} [{}]", path, format_actions(actions))
        }
        Event::Audit { name, critical } => {
            if *critical {
                format!("audit: {}", name)
            } else {
                format!("audit: {} (critical)", name)
            }
        }
    }
}

