#[derive(Default)]
struct Stats {
    valid: usize,
    invalid: usize,
    missing_id: usize,
    bad_kind: usize,
    bad_ts: usize,
    bad_meta: usize,
}

fn parse_line(line: &str, stats: &mut Stats) -> bool {
    let mut id = "";
    let mut kind = "";
    let mut ts = "";
    let mut meta = "";

    for part in line.split('|') {
        if let Some((k, v)) = part.split_once('=') {
            match k {
                "id" => id = v,
                "kind" => kind = v,
                "ts" => ts = v,
                "meta" => meta = v,
                _ => {}
            }
        }
    }

    if id.is_empty() {
        stats.missing_id += 1;
        stats.invalid += 1;
        return false;
    }

    if !matches!(kind, "click" | "view" | "purchase") {
        stats.bad_kind += 1;
        stats.invalid += 1;
        return false;
    }

    if ts.parse::<u64>().is_err() {
        stats.bad_ts += 1;
        stats.invalid += 1;
        return false;
    }

    if !meta.is_empty() {
        for entry in meta.split(',') {
            if !entry.contains(':') {
                stats.bad_meta += 1;
                stats.invalid += 1;
                return false;
            }
        }
    }

    stats.valid += 1;
    true
}

