    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    Open,
    InProgress,
    Blocked,
    Closed,
}

#[derive(Clone, Copy, Debug)]
enum Event<'a> {
    Opened(&'a str),
    Start(&'a str),
    Block(&'a str),
    Unblock(&'a str),
    Resolve(&'a str),
    Reopen(&'a str),
}

fn apply(status: Option<Status>, event: Event<'_>) -> Status {
    match event {
        Event::Opened(_) => Status::Open,
        Event::Start(_) => Status::InProgress,
        Event::Block(_) => Status::Blocked,
        Event::Unblock(_) => Status::Open,
        Event::Resolve(_) => Status::Closed,
        Event::Reopen(_) => status.unwrap_or(Status::Open),
    }
}

fn ticket_id(event: Event<'_>) -> &'_ str {
    match event {
        Event::Opened(id)
        | Event::Start(id)
        | Event::Block(id)
        | Event::Unblock(id)
        | Event::Resolve(id)
        | Event::Reopen(id) => id,
    }
}

fn label(status: Status) -> &'static str {
    match status {
        Status::Open => "open",
        Status::InProgress => "in_progress",
        Status::Blocked => "blocked",
        Status::Closed => "closed",
    }
}

fn main() {
    let events = [
        Event::Opened("A"),
        Event::Start("A"),
        Event::Block("A"),
        Event::Unblock("A"),
        Event::Resolve("A"),
