        Event::Block("B"),
        Event::Unblock("B"),
        Event::Opened("C"),
        Event::Resolve("C"),
        Event::Reopen("C"),
        Event::Start("C"),
        Event::Resolve("C"),
    ];

    let mut states: BTreeMap<&str, Status> = BTreeMap::new();
    for event in events {
        let id = ticket_id(event);
        let next = apply(states.get(id).copied(), event);
        states.insert(id, next);
    }

    let mut lines = Vec::new();
    for (id, status) in states {
        lines.push(format!("{}:{}", id, label(status)));
    }
    println!("{}", lines.join("\n"));
}
