    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    Open,
    InProgress,
    OnHold,
    Closed,
}

enum Event<'a> {
    Create(&'a str),
    Start(&'a str),
    Hold(&'a str),
    Resume(&'a str),
    Resolve(&'a str),
    Reopen(&'a str),
}

#[derive(Clone, Copy)]
struct Ticket {
    status: Status,
    holds: u32,
}

fn apply_event(ticket: &mut Ticket, event: &Event) {
    match *event {
        Event::Create(_) => {
            ticket.status = Status::Open;
        }
        Event::Start(_) => {
            if ticket.status == Status::Open {
                ticket.status = Status::InProgress;
            }
        }
        Event::Hold(_) => {
            if ticket.status == Status::InProgress {
                ticket.status = Status::OnHold;
            }
        }
        Event::Resume(_) => {
            if ticket.status == Status::OnHold {
                ticket.status = Status::Open;
            }
        }
        Event::Resolve(_) => {
            if ticket.status != Status::Closed {
                ticket.status = Status::Closed;
            }
        }
        Event::Reopen(_) => {
            if ticket.status == Status::Closed {
                ticket.status = Status::InProgress;
            }
        }
    }
}

fn main() {
    let events = vec![
        Event::Create("T1"),
        Event::Start("T1"),
        Event::Hold("T1"),
        Event::Resume("T1"),
        Event::Start("T1"),
        Event::Resolve("T1"),
        Event::Create("T2"),
        Event::Start("T2"),
        Event::Resolve("T2"),
        Event::Reopen("T2"),
        Event::Create("T3"),
        Event::Start("T3"),
        Event::Hold("T3"),
        Event::Resume("T3"),
    ];

    let mut tickets: BTreeMap<&str, Ticket> = BTreeMap::new();

    for event in &events {
        let id = match *event {
            Event::Create(id)
            | Event::Start(id)
            | Event::Hold(id)
            | Event::Resume(id)
            | Event::Resolve(id)
            | Event::Reopen(id) => id,
        };

        let ticket = tickets.entry(id).or_insert(Ticket {
            status: Status::Open,
            holds: 0,
        });

        apply_event(ticket, event);
    }

    for (id, ticket) in tickets {
        let status = match ticket.status {
            Status::Open => "Open",
            Status::InProgress => "InProgress",
            Status::OnHold => "OnHold",
            Status::Closed => "Closed",
        };
        println!("{} => {} (holds: {})", id, status, ticket.holds);
    }
}
"
