    "src/main.rs": "#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    New,
    Paid,
    Packed,
    Shipped,
    Delivered,
    Canceled,
}

#[derive(Clone, Copy)]
enum Event {
    Pay,
    Pack,
    Ship,
    Deliver,
    Cancel,
}

struct Order {
    id: &'static str,
    status: Status,
}

fn apply_event(status: Status, event: Event) -> Status {
    match event {
        Event::Cancel => Status::Canceled,
        Event::Pay => match status {
            Status::New => Status::Paid,
            _ => status,
        },
        Event::Pack => match status {
            Status::Paid => Status::Packed,
            _ => status,
        },
        Event::Ship => match status {
            Status::Packed => Status::Shipped,
            _ => status,
        },
        Event::Deliver => match status {
            Status::Packed | Status::Paid => Status::Delivered,
            _ => status,
        },
    }
}

fn status_name(status: Status) -> &'static str {
    match status {
        Status::New => "new",
        Status::Paid => "paid",
        Status::Packed => "packed",
        Status::Shipped => "shipped",
        Status::Delivered => "delivered",
        Status::Canceled => "canceled",
    }
}

