        ("C", Event::Pay),
        ("C", Event::Deliver),
        ("D", Event::Pay),
        ("D", Event::Pack),
        ("D", Event::Ship),
        ("D", Event::Deliver),
    ];

    for (id, event) in events {
        if let Some(order) = orders.iter_mut().find(|o| o.id == id) {
            order.status = apply_event(order.status, event);
        }
    }

    for order in orders {
        println!("{}: {}", order.id, status_name(order.status));
    }
}
