    "src/main.rs": "#[derive(Clone, Debug)]
struct Config {
    service: String,
    endpoint: String,
    retries: u32,
    timeout_ms: u32,
    dry_run: bool,
    tags: Vec<String>,
}

impl Config {
    fn defaults() -> Self {
        Self {
            service: "ingest".to_string(),
            endpoint: "https://default.example/api".to_string(),
            retries: 2,
            timeout_ms: 1000,
            dry_run: false,
            tags: vec!["base".to_string()],
        }
