#[derive(Clone, Debug, Default)]
struct Config {
    mode: Option<&'static str>,
    retry: Option<u32>,
    timeout: Option<u32>,
    features: Vec<&'static str>,
}

fn merge(defaults: Config, file: Config, env: Config, cli: Config) -> Config {
    let mode = defaults.mode.or(file.mode).or(env.mode).or(cli.mode);
    let retry = defaults.retry.or(file.retry).or(env.retry).or(cli.retry);
    let timeout = defaults.timeout.or(file.timeout).or(env.timeout).or(cli.timeout);

