    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum Status {
    Todo,
    InProgress,
    Blocked,
    Closed,
}

impl Status {
    fn label(&self) -> &'static str {
        match self {
            Status::Todo => "Todo",
            Status::InProgress => "InProgress",
            Status::Blocked => "Blocked",
            Status::Closed => "Closed",
        }
    }
}

#[derive(Clone)]
struct Ticket {
    status: Status,
    owner: Option<&'static str>,
    blocked: bool,
    reopenable: bool,
}

impl Ticket {
    fn new() -> Self {
        Self {
            status: Status::Todo,
            owner: None,
            blocked: false,
            reopenable: false,
        }
    }
}

enum Event {
    Start(&'static str),
    Block,
    Unblock,
    Resolve,
    Reopen,
    Transfer(&'static str),
}

fn apply(ticket: &mut Ticket, event: Event) {
    match event {
        Event::Start(owner) => {
            ticket.owner = Some(owner);
            ticket.status = Status::InProgress;
            ticket.blocked = false;
        }
        Event::Block => {
            ticket.status = Status::Blocked;
            ticket.blocked = true;
        }
        Event::Unblock => {
            ticket.blocked = false;
        }
        Event::Resolve => {
            ticket.status = Status::Closed;
            ticket.reopenable = false;
            ticket.blocked = false;
        }
        Event::Reopen => {
            ticket.status = Status::Todo;
            ticket.reopenable = true;
        }
        Event::Transfer(owner) => {
            ticket.owner = Some(owner);
        }
    }
}

