        ("C", Event::Start("cora")),
        ("C", Event::Block),
        ("C", Event::Transfer("none")),
        ("C", Event::Unblock),
        ("C", Event::Block),
    ];

    for (id, event) in events {
        let ticket = tickets.entry(id).or_insert_with(Ticket::new);
        apply(ticket, event);
    }

    let mut lines = Vec::new();
    for (id, t) in tickets {
        let owner = t.owner.unwrap_or("none");
        lines.push(format!(
            "{}: {} [owner={}, blocked={}, reopenable={}]",
            id,
            t.status.label(),
            owner,
            t.blocked,
            t.reopenable
        ));
    }
    print!("{}", lines.join("\n"));
}
