        accumulate(totals, ticket.status, ticket.points);
    }

    let mut lines = Vec::new();
    for team in [Team::Ops, Team::Eng, Team::Sales] {
        let name = team_name(team);
        let t = by_team.get(name).unwrap();
        lines.push(format!(
            "{}: pending={} done={} blocked={} canceled={} active={} points={}",
            name, t.pending, t.done, t.blocked, t.canceled, t.active, t.points
