    "src/lib.rs": "pub fn parse_record(line: &str) -> Result<Vec<(String, String)>, String> {
    let mut out = Vec::new();
    for part in line.split(';') {
        if part.is_empty() {
            continue;
        }
        let (key, value) = part
            .split_once('=')
            .ok_or_else(|| format!("missing '=' in segment: {part}"))?;
        if key.is_empty() {
            return Err("empty key".into());
        }
        if value.is_empty() {
            return Err(format!("empty value for key: {key}"));
        }
        if !key.chars().all(|c| c.is_ascii_lowercase() || c == '_') {
            return Err(format!("invalid key: {key}"));
        }
        if !value.chars().all(|c| c.is_ascii_alphanumeric() || c == '_') {
            return Err(format!("invalid value for key: {key}"));
        }
        out.push((key.to_string(), value.to_string()));
    }
    if out.is_empty() {
        return Err("no fields".into());
    }
    Ok(out)
}

