  "case_id": "ticket_state_audit_summary",
  "bug_category": "state_transitions",
  "difficulty": "medium",
  "user": "In the Rust crate at {project_root}, run the program and report the exact stdout it produces.",
  "expected_tool_sequence": [
    "cargo_run"
  ],
  "expected_output": "A100: Closed
A101: Reopened
A102: InProgress
A103: Closed",
  "files": {
    "Cargo.toml": "[package]
name = "ticket_state_audit_summary"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum State {
    Open,
    InProgress,
    Blocked,
    Closed,
    Reopened,
}

#[derive(Clone, Copy)]
enum Event {
    Create,
    Start,
    Block,
    Unblock,
    Resolve,
    Reopen,
}

fn apply_event(current: Option<State>, event: Event) -> Option<State> {
    use Event::*;
    use State::*;

    match (current, event) {
        (None, Create) => Some(Open),
        (Some(Open), Start) => Some(InProgress),
        (Some(Blocked), Unblock) => Some(InProgress),
        (Some(InProgress), Block) => Some(Blocked),
        (Some(InProgress), Resolve) | (Some(Blocked), Resolve) => Some(Closed),
        (Some(Closed), Reopen) => Some(Reopened),
        (Some(Reopened), Start) => Some(InProgress),
        (Some(Reopened), Resolve) => Some(Closed),
        (state, _) => state,
    }
}

fn state_name(state: State) -> &'static str {
    match state {
        State::Open => "Open",
        State::InProgress => "InProgress",
        State::Blocked => "Blocked",
        State::Closed => "Closed",
        State::Reopened => "Reopened",
    }
}

fn main() {
    let events = [
        ("A100", Event::Create),
        ("A100", Event::Start),
        ("A100", Event::Resolve),
        ("A101", Event::Create),
        ("A101", Event::Start),
        ("A101", Event::Resolve),
        ("A101", Event::Reopen),
        ("A102", Event::Create),
        ("A102", Event::Start),
        ("A102", Event::Block),
        ("A102", Event::Unblock),
        ("A103", Event::Create),
        ("A103", Event::Resolve),
        ("A103", Event::Start),
        ("A103", Event::Resolve),
        ("A102", Event::Resolve),
    ];

    let mut states: BTreeMap<&str, Option<State>> = BTreeMap::new();

    for (id, event) in events {
        let current = states.get(id).copied().flatten();
        let next = apply_event(current, event);
        states.insert(id, next);
    }

    let mut lines = Vec::new();
    for (id, state) in states {
        if let Some(state) = state {
            lines.push(format!("{}: {}", id, state_name(state)));
        }
    }

    print!("{}", lines.join("\n"));
}
"
  },
