}

fn describe(event: &OrderEvent) -> String {
    match event {
        OrderEvent::Create { items } => format!("reserve stock for {} sku(s)", items.len()),
        OrderEvent::Pay(payment) => match payment {
            Payment::Card { cents, verified } if *verified && *cents <= 10_000 => {
